const jobs = $input.first().json.jobs;

return jobs
.filter(job => {
  const title = (job.title || "").toLowerCase();

  // Fresher-friendly roles
  const relevant =
    title.includes("data analyst") ||
    title.includes("business analyst") ||
    title.includes("reporting analyst") ||
    title.includes("python developer") ||
    title.includes("software engineer") ||
    title.includes("software developer") ||
    title.includes("associate software engineer") ||
    title.includes("associate engineer") ||
    title.includes("junior developer") ||
    title.includes("graduate engineer") ||
    title.includes("qa engineer") ||
    title.includes("test engineer") ||
    title.includes("automation engineer") ||
    title.includes("technical support") ||
    title.includes("it support") ||
    title.includes("power bi") ||
    title.includes("data engineer") ||
    title.includes("ai intern") ||
    title.includes("machine learning intern") ||
    title.includes("data analyst intern") ||
    title.includes("software engineer intern") ||
    title.includes("software developer intern") ||
    title.includes("python intern") ||
    title.includes("data science intern") ||
    title.includes("ai agent") ||
    title.includes("ai automation") ||
    title.includes("prompt engineer");

  // Exclude senior roles
  const senior =
    title.includes("senior") ||
    title.includes("lead") ||
    title.includes("manager") ||
    title.includes("staff") ||
    title.includes("principal") ||
    title.includes("director") ||
    title.includes("architect");

  return relevant && !senior;
})

// Reduce AI Agent load
.slice(0, 10)

.map(job => ({
  json: job
}));

return items.filter(item => {
  const title = (item.json.title || "").toLowerCase();
  const location = (item.json.candidate_required_location || "").toLowerCase();

  const blocked = [
    "french",
    "german",
    "spanish",
    "japanese",
    "korean",
    "mandarin",
    "senior",
    "staff",
    "principal",
    "director",
    "manager",
    "lead"
  ];

  if (blocked.some(word => title.includes(word))) {
    return false;
  }

  if (
    location &&
    !location.includes("worldwide") &&
    !location.includes("india") &&
    !location.includes("anywhere")
  ) {
    return false;
  }

  return true;
});
